    "title_i18n": {"eu":"Bizitza Soziala","ko":"사교 생활","zh":"社交生活","vi":"Đời sống xã hội","ja":"社交生活","ru":"Социальная жизнь","mn":"Нийгмийн амьдрал","uz":"Ijtimoiy hayot","ar":"الحياة الاجتماعية"},
